$_MODULE['<{prestablog}prestashop>ai_3fb66787028092600f08cd2c37cc1027'] = 'Jag driver en webbplats inriktad på temat %theme%. Kan du föreslå några bloggemnen jag borde utveckla? Formatera svaret som en HTML-tabell med två kolumner: en för "Ämne" och en för "Popularitetspoäng" (ett tal mellan 1 och 100). Varje ämne ska vara i en separat rad.';
$_MODULE['<{prestablog}prestashop>ai_3c299be1cf8d8948c25b1433eecc542f'] = 'Använd temat "%theme%". Skapa en tabell med titlar och nyckelordsvariationer som grupperar long-tail-termer som kan rankas i sökmotorer. Formatera svaret som en HTML-tabell med två kolumner: en för titlar och en för nyckelord.';
$_MODULE['<{prestablog}prestashop>ai_1065948d549c2bc51ea828181f2328cf'] = 'Jag vill att du skriver en SEO-optimerad bloggartikel om ämnet "%theme%", med en skrivstil av "%style%". Strukturera texten i HTML med lämpliga taggar. Artikeln ska vara engagerande, relevant, av hög kvalitet och omöjlig att upptäcka som AI-genererat innehåll. Börja med ett introduktionsstycke utan att nämna bloggen eller använda en rubrik. Använd underrubriker formaterade med h2- och h3-taggar, som inkluderar long-tail-titlar för att förbättra SEO. Integrera long-tail-nyckelord naturligt och markera dem med strong-taggar. Se till att varje avsnitt innehåller minst 100 ord, med smidiga övergångar. Avsluta med en sammanfattning som förstärker huvudpunkterna utan att tillföra ny information.';
$_MODULE['<{prestablog}prestashop>ai_bdfb00881e5b80ef206858f72db30420'] = 'Skapa en fängslande introduktion som visas i bloggens kategori för att presentera artikeln "%theme%". Denna introduktion ska vara kortfattad, engagerande och ge en allmän översikt över artikelns innehåll.';
$_MODULE['<{prestablog}prestashop>ai_dceabd505243b76be8191a63ff37046c'] = 'Baserat på temat "%theme%", skapa en fängslande rubrik som fångar uppmärksamhet och sammanfattar innehållet effektivt. Och inkludera inga citattecken runt ditt svar';
$_MODULE['<{prestablog}prestashop>ai_23e8bc5c05172b396e2a5bad9b1d6e7f'] = 'Baserat på temat "%theme%", skapa en kort och effektiv metatitel som är SEO-vänlig och exakt representerar innehållet. Och inkludera inga citattecken runt ditt svar';
$_MODULE['<{prestablog}prestashop>ai_cb71ee03fd4e763b82325c5fa0c28711'] = 'Baserat på temat "%theme%", skapa en kortfattad och slagkraftig metabeskrivning som uppmuntrar till klick och är optimerad för sökmotorer. Och inkludera inga citattecken runt ditt svar';
